module top_module(pb_debounced, pb, clk);output pb_debounced; 
    input pb; 
    input clk;
    reg [3:0] DFF; 
    always @(posedge clk) begin
      DFF[3:1] <= DFF[2:0];
      DFF[0] <= pb;
    end
    wire neg_pb_debounced = (DFF == 4'b1111);
    assign pb_debounced = neg_pb_debounced ? 1'b1 : 1'b0;endmodule
